import { Box, Chip, Autocomplete, TextField } from '@mui/material';
import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom/cjs/react-router-dom.min';
import * as actions from '../../redux/actions';
import { useDispatch, useSelector } from 'react-redux';
import { useGeolocated } from 'react-geolocated';
import findProjectwithLocation from '../../utils/functions/findProjectwithLocation';

import { Clock, DollarSign } from 'react-feather';
import { Link } from 'react-router-dom/cjs/react-router-dom.min';

export default function ManpowerTimestamp() {
  const dispatch = useDispatch();
  const { id } = useParams();
  const project = useSelector((state) => state.project);
  const [currentProject, setCurrentProject] = useState(null);
  const [manualProject, setManualProject] = useState(null);

  const {
    coords,
    isGeolocationAvailable,
    isGeolocationEnabled,
  } = useGeolocated({
    positionOptions: {
      enableHighAccuracy: false,
    },
    userDecisionTimeout: 5000,
  });

  const foundProject = findProjectwithLocation(coords, project, 500);

  useEffect(() => {
    dispatch(actions.projectAll({ time_tracking_enabled: true }));
  }, []);

  useEffect(() => {
    if (foundProject && foundProject.length > 0) {
      setCurrentProject(foundProject[0]?.item); // findProjectwithLocation returns [{item, distance}]
      setManualProject(null);
    } else {
      setCurrentProject(null);
    }
  }, [JSON.stringify(foundProject)]); 
  // Note: foundProject is a new array every render, so we need stable dependency or checking content. 
  // However, findProjectwithLocation returns a new array. stringify is a quick dirty fix or we can rely on coords change if we memorized result.
  // Better: use JSON.stringify(foundProject) or just rely on manual selection if foundProject is empty.
  
  // Actually, wait. findProjectwithLocation returns `[{item, distance}]`. 
  // My previous edit used `setCurrentProject(foundProject[0])` which would set `{item: ..., distance: ...}` as currentProject. 
  // But `currentProject.name` usage implies it expects the project object directly. 
  // So it should be `foundProject[0].item`.
  // I need to correct this.

  const activeProject = currentProject || manualProject;

  return (
    <div>
      <div>
        <div className="flex flex-col justify-center h-screen bg-gray-100">
          <div className="flex flex-col justify-center items-center">
            <div className=" text-2xl lg:text-4xl font-bold text-theme-600  ">
              ระบบลงเวลาเข้า-ออกงาน
            </div>
            <div className="border-b-2 border-theme-600 w-1/2 my-2 "> </div>
            <div className="text-xl text-center">
              {' '}
              <b className="text-theme-600">โครงการ :</b> {activeProject?.name}{' '}
            </div>
          </div>
          <div className=" w-full lg:w-1/2 mx-auto">
             {!currentProject && (
               <Box sx={{ p: 2, display: 'flex', justifyContent: 'center' }}>
                 <Autocomplete
                   options={project?.rows || []}
                   getOptionLabel={(option) => option.name || ''}
                   value={manualProject}
                   onChange={(event, newValue) => {
                     setManualProject(newValue);
                   }}
                   sx={{ width: 300 }}
                   renderInput={(params) => (
                     <TextField {...params} label="เลือกโครงการ" variant="outlined" />
                   )}
                 />
               </Box>
             )}
          
            {activeProject?.time_tracking_enabled ? (
              <Box sx={{ minWidth: 200 }}>
                <div className="flex justify-center gap-5 p-6">
                  <div className="w-1/2">
                    <Link to={`/manpower/timestamp/checkin/${activeProject?._id}`}>
                      <div className="bg-green-600 shadow rounded text-center p-5 transition-transform transform hover:scale-105">
                        <div className="flex justify-center">
                          <Clock size={50} color="white" />
                        </div>
                        <p className="text-white mt-4">เข้างาน</p>
                      </div>
                    </Link>
                  </div>
                  <div className="w-1/2">
                    <Link to={`/manpower/timestamp/checkout/${activeProject?._id}`}>
                      <div className="bg-red-600 shadow rounded text-center p-5 transition-transform transform hover:scale-105">
                        <div className="flex justify-center">
                          <Clock size={50} color="white" />
                        </div>
                        <p className="text-white mt-4">ออกงาน</p>
                      </div>
                    </Link>
                  </div>
                </div>
              </Box>
            ) : activeProject ? (
              <div className="text-center text-2xl py-4  text-red-600">
                <Chip
                  label="ไม่อยู่ในช่วงเวลาที่สามารถบันทึกได้"
                  size="large"
                  color="error"
                />
              </div>
            ) : null}
          </div>
        </div>
      </div>
    </div>
  );
}
